PlayerListener = {}

function PlayerListener:init()
    --Listener.registerCallBack(UpdateUserListEvent, function()
    --    if GUIBattleInfo then
    --        GUIBattleInfo:updatePlayerListUI()
    --    end
    --end)

    Listener.registerCallBack(GoAppShopEvent, function(type)
        GUIStore:hide()
        if type == Define.Money.KEY then
            GUIStore:show(StoreId.CubeStore, 8)
        else
            GUIStore:show(StoreId.CubeStore)
        end
        return false
    end)

    Listener.registerCallBack(PlayerPlayBaseActionEvent, self.onPlayerPlayAction)
    Listener.registerCallBack(PlayerPlayUpperActionEvent, self.onPlayerPlayAction)
    --Listener.registerCallBack(ClickScenePlayActionEvent, self.onClickScenePlayAction)
    Listener.registerCallBack(AttackEntityEvent, self.onAttackEntity)

    CommonDataEvents:registerCallBack("PlayerIntoTeamResource", self.onPlayerIntoTeamResource, DataBuilderProcessor)
    CommonDataEvents:registerCallBack("NotPlayerTeamResource", self.onNotPlayerIntoTeamResource, DataBuilderProcessor)
end

function PlayerListener.onPlayerPlayAction(player, _, skill)
    if not isGameStart then
        return
    end
    if skill.value ~= "attack2" then
        return
    end
    local item = Item.getItemById(player:getHeldItemId())
    if not item then
        return
    end
    local class = item:getClassName()
    if class == "ItemSword" or class == "ItemPickaxe" or class == "ItemAxe" or class == "ItemShears" then
        local info = GameInfoManager:getPlayerInfo(player:getPlatformUserId())
        if not info then
            return
        end
        skill.value = info:getValue("attack_skill_name")
    end
end

local function getCameraPos(offset)
    local camera = SceneManager.Instance():getMainCamera()
    local pos = camera:getPosition()
    local dir = camera:getDirection()
    local right = camera:getRight()
    local down = VectorUtil.sub3(VectorUtil.ZERO, camera:getUp())
    local frontOff, rightOff, downOff = offset.x, offset.y, offset.z
    pos.x = pos.x + dir.x * frontOff
    pos.y = pos.y + dir.y * frontOff
    pos.z = pos.z + dir.z * frontOff
    pos.x = pos.x + right.x * rightOff
    pos.y = pos.y + right.y * rightOff
    pos.z = pos.z + right.z * rightOff
    pos.x = pos.x + down.x * downOff
    pos.y = pos.y + down.y * downOff
    pos.z = pos.z + down.z * downOff
    return pos
end

function PlayerListener.onClickScenePlayAction()
    if not GUIBedWarSetting then
        return true
    end
    if not GUIBedWarSetting:isFirstPerspective() then
        return true
    end
    local item = Item.getItemById(Game:getPlayer():getHeldItemId())
    if not item then
        return true
    end
    local class = item:getClassName()
    if not (class == "ItemSword" or class == "ItemPickaxe" or class == "ItemAxe" or class == "ItemShears") then
        return true
    end
    local info = GameInfoManager:getPlayerInfo(Game:getPlayer():getPlatformUserId())
    if not info then
        return true
    end
    local skillName = info:getValue("attack_skill_name")
    if skillName == "attack2" then
        return true
    end
    local setting = CustomShopSwordLight:getSettingBySceneAction(skillName)
    if not setting or not setting.Effect then
        return true
    end
    local pos = getCameraPos(setting.Offset)
    local effect = EngineWorld:addSimpleEffect(setting.Effect, pos, -Game:getPlayer():getYaw(), -1, setting.Scale.x, setting.Scale.y, setting.Scale.z)
    if not effect then
        return
    end
    effect.mPitch = -Game:getPlayer():getPitch()
    LuaTimer:scheduleTimerWithEnd(function()
        effect.mPosition = getCameraPos(setting.Offset)
    end, function()
        effect.mDuration = 0
    end, 10, 80)
    return true
end

function PlayerListener.onAttackEntity(entityId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if not player then
        return true
    end
    return PlayerListener.onClickScenePlayAction()
end

function PlayerListener.onPlayerIntoTeamResource(data)
    local userId = data:getParam("userId")
    local pointId = data:getNumberParam("pointId")
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end
    ResourcePointConfig:onPlayerIntoTeamResource(player:getEntityId(), pointId)
end

function PlayerListener.onNotPlayerIntoTeamResource(data)
    local pointId = data:getNumberParam("pointId")
    ResourcePointConfig:onNotPlayerIntoResource(pointId)
end